<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <title>WastedToken Mint</title>
  <style>
    body { margin:0; background:#111; color:#fff; font-family:sans-serif; }
    canvas { display:block; margin:auto; width:90vw; height:60vh; max-width:800px; border-radius:5%; box-shadow:0 0 30px #fff2; background:#222; }
    .about { padding:40px 20px; text-align:center; font-size:1.5em; line-height:1.6; max-width:800px; margin:auto; }
    .collection-grid { display:grid; grid-template-columns:repeat(2, 1fr); gap:30px; padding:40px 20px; max-width:900px; margin:auto; }
    .edition { border-radius:15px; overflow:hidden; background:#333; box-shadow:0 0 20px #fff1; position:relative; text-align:center; }
    .edition-canvas { width:100%; height:200px; display:block; }
    button.buy { margin-top:15px; padding:10px 20px; background:#ff4; color:#000; border:none; font-weight:bold; cursor:pointer; }
    .sold-out, .coming-soon { position:absolute; top:50%; left:50%; transform:translate(-50%,-50%); font-size:1.2em; text-transform:uppercase; background:rgba(0,0,0,0.7); padding:8px 16px; border-radius:4px; }
    .coming-soon { color:#ff9; }
    @media (max-width: 700px) {
      .collection-grid { grid-template-columns:1fr; }
    }
  </style>
</head>
<body>
  <canvas id="coin-hero"></canvas>
  <section class="about">
    WastedToken Mint crafts limited-edition challenge coins with precision and artistry. Each coin is a physical token of commitment, rarity, and prestige. Our reeded edges, raised reliefs, and dynamic minting process ensure every piece is a collector's treasure.
  </section>
  <div class="collection-grid">
    <div class="edition" data-edition="bronze" data-state="available">
      <canvas class="edition-canvas"></canvas>
      <button class="buy">Add to cart</button>
    </div>
    <div class="edition" data-edition="silver" data-state="available">
      <canvas class="edition-canvas"></canvas>
      <button class="buy">Add to cart</button>
    </div>
    <div class="edition" data-edition="gold" data-state="sold-out">
      <canvas class="edition-canvas"></canvas>
      <span class="sold-out">SOLD OUT</span>
    </div>
    <div class="edition" data-edition="black" data-state="coming-soon">
      <canvas class="edition-canvas"></canvas>
      <span class="coming-soon">MINTING NEXT WINTER</span>
    </div>
  </div>

  <script>
(function() {
  const canvas = document.getElementById('coin-hero');
  let gl, program, time = 0;
  let isPaused = false;

  function createShader(type, source) {
    const shader = gl.createShader(type);
    gl.shaderSource(shader, source);
    gl.compileShader(shader);
    return shader;
  }

  function initWebGL() {
    gl = canvas.getContext('webgl');
    if (!gl) return;

    // Vertex Shader
    const vsSource = `
      attribute vec2 aPosition;
      uniform mat4 uModelViewMatrix;
      varying vec3 vNormal;
      varying vec3 vPos;
      void main() {
        vNormal = normalize(vec3(aPosition, 0.0));
        vPos = vec3(aPosition * cos(time) + sin(time), 0.0);
        gl_Position = uModelViewMatrix * vec4(vPos, 1.0);
      }
    `;
    const fsSource = `
      precision highp float;
      varying vec3 vNormal;
      varying vec3 vPos;
      uniform float time;
      void main() {
        vec2 uv = vPos.xy;
        float radius = length(uv);
        if (radius > 1.0) discard;

        // Reeds
        float reed = 0.0;
        for(float i=0.98; i>0.95; i-=0.002)
          reed += smoothstep(i, i+0.001, radius);

        // Light & view vectors
        vec3 lightDir = normalize(vec3(1.0, 1.0, 1.0));
        vec3 viewDir = normalize(-vPos);
        float diff = max(dot(vNormal, -lightDir), 0.0);
        vec3 reflectDir = normalize(reflect(lightDir, vNormal));
        float spec = pow(max(dot(viewDir, reflectDir), 0.0), 64.0);

        // Front/Back faces
        bool frontFace = dot(vPos.xy, vec2(cos(time*1.5), sin(time*1.5))) > 0.9;
        vec3 baseColor = mix(vec3(0.8, 0.7, 0.6), vec3(0.4, 0.4, 0.4), step(0.99, radius));
        if (frontFace) {
          // Front emblem
          float emblem = smoothstep(0.15, 0.2, length(uv)) * 
                        smoothstep(0.3, 0.28, length(uv));
          baseColor += vec3(emblem * 0.3);
        } else {
          // Back text
          float txt = step(0.4, abs(mod(length(uv), 0.1))) * 
                     step(0.5, radius) * smoothstep(0.98, 0.96, radius);
          baseColor += vec3(txt * 0.2);
        }

        gl_FragColor = vec4(baseColor + diff*vec3(0.7)+spec*vec3(1.0), 1.0);
      }
    `;

    const vs = createShader(gl.VERTEX_SHADER, vsSource);
    const fs = createShader(gl.FRAGMENT_SHADER, fsSource);
    program = gl.createProgram();
    gl.attachShader(program, vs);
    gl.attachShader(program, fs);
    gl.linkProgram(program);

    // Buffers
    const positions = [];
    for (let i=0; i<=360; i++) {
      let angle = i * Math.PI/180;
      positions.push(Math.cos(angle), Math.sin(angle));
    }
    const buffer = gl.createBuffer();
    gl.bindBuffer(gl.ARRAY_BUFFER, buffer);
    gl.bufferData(gl.ARRAY_BUFFER, new Float32Array(positions), gl.STATIC_DRAW);

    // Attributes
    const aPositionLoc = gl.getAttribLocation(program, 'aPosition');
    gl.enableVertexAttribArray(aPositionLoc);
    gl.vertexAttribPointer(aPositionLoc, 2, gl.FLOAT, false, 0, 0);

    // Uniforms
    program.timeLoc = gl.getUniformLocation(program, 'time');

    render();
  }

  function render() {
    if (!isPaused) time += 0.016;
    gl.viewport(0, 0, canvas.width, canvas.height);
    gl.clearColor(0.1, 0.1, 0.1, 1);
    gl.clear(gl.COLOR_BUFFER_BIT | gl.DEPTH_BUFFER_BIT);

    gl.useProgram(program);
    gl.uniform1f(program.timeLoc, time * Math.PI*2);
    gl.drawArrays(gl.TRIANGLE_FAN, 0, positions.length/2);

    requestAnimationFrame(render);
  }

  canvas.width = window.innerWidth;
  canvas.height = window.innerHeight;
  initWebGL();

  // API
  window.demo = {
    canvas,
    setTime(t) {
      time = t * Math.PI*2;
      gl.useProgram(program);
      gl.uniform1f(program.timeLoc, time);
      render();
    },
    pause() {
      isPaused = true;
    }
  };

  // Editions
  const editions = document.querySelectorAll('.edition');
  function drawEdition(ctx, type) {
    const w = ctx.canvas.width;
    const h = ctx.canvas.height;
    const centerX = w/2;
    const centerY = h/2;
    const radius = Math.min(w,h)/3;

    // Reeds
    for (let i=0.98; i>0.95; i-=0.002) {
      ctx.beginPath();
      ctx.arc(centerX, centerY, radius*i, 0, Math.PI*2);
      ctx.strokeStyle = `rgba(255,255,255,${i-0.95})`;
      ctx.lineWidth = 1;
      ctx.stroke();
    }

    // Base color
    const colors = {
      bronze: ['#cd7f32', '#b86c2a'],
      silver: ['#e0e0e0', '#a0a0a0'],
      gold: ['#ffd700', '#ffcc00'],
      black: ['#1a1a1a', '#0d0d0d']
    };
    const [c1, c2] = colors[type];

    // Gradient
    const grad = ctx.createRadialGradient(centerX, centerY, 0, centerX, centerY, radius);
    grad.addColorStop(0, c1);
    grad.addColorStop(1, c2);
    ctx.fillStyle = grad;
    ctx.beginPath();
    ctx.arc(centerX, centerY, radius, 0, Math.PI*2);
    ctx.fill();

    // Front/Back
    if (type === 'gold' || type === 'black') {
      // Back face text
      ctx.save();
      ctx.translate(centerX, centerY);
      ctx.fillStyle = '#fff';
      ctx.font = `${radius/4}px Arial`;
      ctx.textAlign = 'center';
      ctx.fillText("10,000 TOKENS", 0, radius/3);
      ctx.restore();
    } else {
      // Front emblem
      ctx.save();
      ctx.translate(centerX, centerY);
      const grad2 = ctx.createRadialGradient(0, -radius*0.4, 0, 0, -radius*0.4, radius*0.15);
      grad2.addColorStop(0, '#fff');
      grad2.addColorStop(1, '#aaa');
      ctx.fillStyle = grad2;
      ctx.beginPath();
      ctx.arc(0, -radius*0.4, radius*0.15, 0, Math.PI*2);
      ctx.fill();
      ctx.restore();
    }
  }

  editions.forEach(ed => {
    const canvas = ed.querySelector('.edition-canvas');
    canvas.width = window.innerWidth;
    canvas.height = 200;
    drawEdition(canvas.getContext('2d'), ed.dataset.edition);

    if (ed.dataset.state === 'available') return;
    ed.querySelector('.buy')?.remove();
  });

  // Responsive
  window.addEventListener('resize', () => {
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
    editions.forEach(ed => {
      const c = ed.querySelector('.edition-canvas');
      c.width = window.innerWidth;
      c.height = 200;
      drawEdition(c.getContext('2d'), ed.dataset.edition);
    });
  });

})();
  </script>
</body>
</html>
